<script setup lang="ts">import{onMounted,ref}from"vue";import{useRoute}from"vue-router";import{Sparkles,Stethoscope,HeartPulse,ShieldPlus}from"lucide-vue-next";import{api,type Department,type Doctor,type Hospital}from"../api";import PageHeader from"../components/PageHeader.vue";import DoctorCard from"../components/DoctorCard.vue";const route=useRoute(),department=ref<Department>(),doctors=ref<Doctor[]>([]),hospitals=ref<Hospital[]>([]);onMounted(async()=>{const id=Number(route.params.id);department.value=await api.department(id);[doctors.value,hospitals.value]=await Promise.all([api.doctors({departmentId:id}),api.hospitals()])});</script><template><main v-if="department"><PageHeader :title="department.name"/><section class="department-banner"><div><p>{{department.name}}问题</p><h1><em>预约</em>挂号</h1></div><Stethoscope/></section><section class="symptom-grid"><div v-for="(x,i) in ['常见疾病','专病门诊','复诊开药','健康咨询','症状筛查','检查解读','慢病管理','术后随访']"><component :is="[Sparkles,Stethoscope,HeartPulse,ShieldPlus][i%4]"/><span>{{x}}</span></div></section><section class="department-promo"><article><h2>名医就诊</h2><p>优质专家号源</p><button @click="$router.push('/doctors')">立即挂号</button></article><article><h3>专科专病</h3><p>{{department.description}}</p></article></section><section class="recommend"><header><h2>热门医生</h2><p>{{department.hospitalName}}</p></header><DoctorCard v-for="d in doctors" :key="d.id" :doctor="d"/></section></main>
</template>
